import{_ as t,c as r,o as i,ag as o}from"./chunks/framework.Dj4VfQLU.js";const u=JSON.parse('{"title":"Vehicle Types & Pricing Configuration","description":"","frontmatter":{"icon":"car-side"},"headers":[],"relativePath":"vehicle-types-and-pricing-configuration.md","filePath":"vehicle-types-and-pricing-configuration.md"}'),n={name:"vehicle-types-and-pricing-configuration.md"};function a(s,e,d,l,c,g){return i(),r("div",null,e[0]||(e[0]=[o('<h1 id="vehicle-types-pricing-configuration" tabindex="-1">Vehicle Types &amp; Pricing Configuration <a class="header-anchor" href="#vehicle-types-pricing-configuration" aria-label="Permalink to &quot;Vehicle Types &amp; Pricing Configuration&quot;">​</a></h1><p>BetterTaxi provides a highly flexible and modular pricing engine that allows businesses to define <strong>vehicle types, pricing logic, order types, and geographic overrides</strong> — all directly from the Admin Panel under:</p><blockquote><p><strong>Settings → Pricing</strong></p></blockquote><p>This section enables you to tailor your service model to local conditions, regulatory environments, and customer expectations.</p><hr><h4 id="🧭-structure-overview" tabindex="-1">🧭 Structure Overview <a class="header-anchor" href="#🧭-structure-overview" aria-label="Permalink to &quot;🧭 Structure Overview&quot;">​</a></h4><p>Under <strong>Settings → Pricing</strong>, you can configure:</p><ol><li><strong>Categories</strong> (e.g., Taxi, Bike, Truck)</li><li><strong>Services</strong> under each category (e.g., Economy Taxi, Premium Bike)</li><li><strong>Pricing rules and multipliers</strong></li><li><strong>Geographic overrides (A-to-B pricing zones)</strong></li></ol><hr><h4 id="🗂️-categories" tabindex="-1">🗂️ Categories <a class="header-anchor" href="#🗂️-categories" aria-label="Permalink to &quot;🗂️ Categories&quot;">​</a></h4><p>Categories group services in the user interface. Each category appears as a <strong>tab</strong> in the customer app unless only one category is defined (in which case the tab bar is hidden).</p><p>Examples:</p><ul><li>&quot;Taxi&quot;, &quot;Bike Delivery&quot;, &quot;Truck Transport&quot;</li><li>Or just a single category like &quot;All Rides&quot;</li></ul><hr><h4 id="🚗-service-configuration" tabindex="-1">🚗 Service Configuration <a class="header-anchor" href="#🚗-service-configuration" aria-label="Permalink to &quot;🚗 Service Configuration&quot;">​</a></h4><p>Each <strong>Service</strong> under a category defines how a ride or delivery is priced and what types of orders it supports.</p><p><strong>Supported Fields</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Supported Order Types</strong></td><td>Multi-select: <code>ride</code>, <code>parcel delivery</code>, <code>food delivery</code>, <code>shop delivery</code>. The last two integrate with BetterShop.</td></tr><tr><td><strong>Base Fare</strong></td><td>Flat amount charged at the start of the trip</td></tr><tr><td><strong>Per Hundred Meters</strong></td><td>Distance-based fare; use conversion to align with miles (apps support both)</td></tr><tr><td><strong>Per Minute Wait</strong></td><td>Rate charged if the rider selects wait time at booking</td></tr><tr><td><strong>Per Minute Ride</strong></td><td>Time-based fare (calculated using real-time Google traffic data)</td></tr><tr><td><strong>Minimum Search Distance</strong></td><td>How far (in meters) the system will look for drivers — set this high enough to avoid &quot;no drivers found&quot; errors</td></tr><tr><td><strong>Minimum/Maximum Ride Distance</strong></td><td>Minimum and maximum allowed distance for a trip</td></tr><tr><td><strong>Prepay Percent</strong></td><td>Value between <code>0-100</code>; determines how much must be prepaid before order creation. Setting to <code>0</code>removes upfront payment (common in trust-based cultures).</td></tr><tr><td><strong>Rounding Factor</strong></td><td>E.g., <code>0.1</code> rounds 4.327 to 4.3. Useful for pricing clarity in receipts</td></tr><tr><td><strong>Minimum Ride Fee</strong></td><td>The lowest fee allowed for a trip, regardless of calculation</td></tr><tr><td><strong>Cancellation Fee</strong></td><td>Charged when a ride is canceled after a certain threshold or conditions</td></tr><tr><td><strong>Driver’s Share of Cancel Fee</strong></td><td>Portion of the cancellation fee credited to the driver</td></tr></tbody></table><hr><h4 id="📈-pricing-multipliers" tabindex="-1">📈 Pricing Multipliers <a class="header-anchor" href="#📈-pricing-multipliers" aria-label="Permalink to &quot;📈 Pricing Multipliers&quot;">​</a></h4><p>Multipliers allow dynamic pricing adjustments based on <strong>time, distance, day, or seasonality</strong>.</p><p><strong>Available Multipliers</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Example</th></tr></thead><tbody><tr><td><strong>Time of Day</strong></td><td>12:00 PM – 2:00 PM → 1.5x multiplier</td></tr><tr><td><strong>Distance</strong></td><td>&gt;2 km → apply 0.8x (discount or surcharge)</td></tr><tr><td><strong>Weekdays</strong></td><td>Monday-Friday → 1.2x</td></tr><tr><td><strong>Date Range</strong></td><td>Holidays or special events → 2.0x</td></tr></tbody></table><p>You can define <strong>multiple stacked rules</strong>, and the system will apply them in order of priority.</p><hr><h4 id="📦-service-options" tabindex="-1">📦 Service Options <a class="header-anchor" href="#📦-service-options" aria-label="Permalink to &quot;📦 Service Options&quot;">​</a></h4><p>Add-ons such as <strong>pets</strong>, <strong>luggage</strong>, or <strong>extra stops</strong> can be configured as optional service modifiers.</p><ul><li>Can be <strong>free</strong> or <strong>charged</strong></li><li>Displayed as checkboxes in the app during booking</li><li>Help personalize rides or deliveries</li></ul><hr><h4 id="🌍-region-assignment" tabindex="-1">🌍 Region Assignment <a class="header-anchor" href="#🌍-region-assignment" aria-label="Permalink to &quot;🌍 Region Assignment&quot;">​</a></h4><p>Each pricing schema must be linked to a <strong>region</strong>. This controls:</p><ul><li>Which users see the pricing</li><li>Currency used (defined at the region level)</li><li>Operational boundaries (defined via geofencing)</li></ul><blockquote><p>Make sure all regions assigned to the pricing have same currency.</p></blockquote><hr><h4 id="🗺️-override-zones-geographic-a→b-pricing" tabindex="-1">🗺️ Override Zones (Geographic A→B Pricing) <a class="header-anchor" href="#🗺️-override-zones-geographic-a→b-pricing" aria-label="Permalink to &quot;🗺️ Override Zones (Geographic A→B Pricing)&quot;">​</a></h4><p>BetterTaxi allows you to define <strong>custom pricing between specific geofenced areas</strong>, bypassing the default fare calculation.</p><p>Use the <strong>&quot;Override Zones&quot;</strong> tab in the Pricing section to:</p><ul><li>Select <strong>Geofence A → Geofence B</strong></li><li>Define a <strong>fixed price</strong> (e.g., Airport → Downtown = $30 flat)</li><li>Apply rules to specific time ranges or dates if needed</li></ul><p>This is useful for:</p><ul><li>Flat-rate airport transfers</li><li>Corporate routes</li><li>Long-distance point-to-point pricing</li></ul><blockquote><p>Overrides take priority over the regular pricing model when both zones are matched.</p></blockquote><hr><h4 id="🧠-example-setup" tabindex="-1">🧠 Example Setup <a class="header-anchor" href="#🧠-example-setup" aria-label="Permalink to &quot;🧠 Example Setup&quot;">​</a></h4><p>Let’s say you&#39;re launching in NYC:</p><ul><li><strong>Categories</strong>: Taxi, Bike Delivery</li><li><strong>Services</strong>: <ul><li>Economy Taxi (supports: ride, ride share)</li><li>Premium Bike (supports: parcel delivery)</li></ul></li><li><strong>Pricing</strong>: <ul><li>Base fare: $3.00</li><li>$0.75 per 100m</li><li>$0.40 per minute ride</li><li>$1.00 per minute wait</li></ul></li><li><strong>Multipliers</strong>: <ul><li>1.5x during rush hour</li><li>0.9x for &lt;2km</li></ul></li><li><strong>Overrides</strong>: <ul><li>JFK → Manhattan = $45 fixed</li></ul></li></ul><hr><h4 id="📝-summary" tabindex="-1">📝 Summary <a class="header-anchor" href="#📝-summary" aria-label="Permalink to &quot;📝 Summary&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Feature</th><th>Configured In</th></tr></thead><tbody><tr><td>Vehicle Types &amp; Categories</td><td>Settings → Pricing</td></tr><tr><td>Services &amp; Pricing</td><td>Under each Category</td></tr><tr><td>Regional Assignment</td><td>Attached to Pricing Entity</td></tr><tr><td>Add-on Options</td><td>Per Service</td></tr><tr><td>Geofence A→B Overrides</td><td>Pricing → Override Zones</td></tr><tr><td>Multipliers</td><td>Time, Day, Distance, Range</td></tr></tbody></table><h4 id="👥-driver-incentives-commission-model" tabindex="-1">👥 Driver Incentives &amp; Commission Model <a class="header-anchor" href="#👥-driver-incentives-commission-model" aria-label="Permalink to &quot;👥 Driver Incentives &amp; Commission Model&quot;">​</a></h4><p>BetterTaxi supports flexible commission structures to manage how drivers are paid and how platform revenue is collected. This model is <strong>defined per pricing configuration</strong> and can optionally integrate with <strong>partner revenue sharing</strong> through the <strong>Partnership Module</strong>.</p><hr><h4 id="💸-commission-models" tabindex="-1">💸 Commission Models <a class="header-anchor" href="#💸-commission-models" aria-label="Permalink to &quot;💸 Commission Models&quot;">​</a></h4><p>You can define one or both of the following commission types for each <strong>Service</strong> under a <strong>Pricing Category</strong>:</p><p><strong>1. Flat Commission</strong></p><ul><li>A fixed amount deducted from each completed trip</li><li>Example: <code>$1.00</code> per ride</li><li>Useful for low-fare or short-distance services</li></ul><p><strong>2. Percentage-Based Commission</strong></p><ul><li>A percentage of the total fare deducted from the driver</li><li>Example: <code>10%</code> of the final ride price</li><li>Dynamic and scales with high-value rides</li></ul><blockquote><p>💡 <strong>Both</strong> flat and percentage-based commissions can be applied simultaneously if needed.</p></blockquote><hr><h4 id="🧾-example" tabindex="-1">🧾 Example <a class="header-anchor" href="#🧾-example" aria-label="Permalink to &quot;🧾 Example&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Ride Fare</th><th>Flat Commission</th><th>% Commission</th><th>Total Commission</th></tr></thead><tbody><tr><td>$12.00</td><td>$1.00</td><td>10% = $1.20</td><td>$2.20</td></tr><tr><td>$5.00</td><td>$1.00</td><td>10% = $0.50</td><td>$1.50</td></tr></tbody></table><hr><h4 id="🤝-revenue-sharing-with-partners" tabindex="-1">🤝 Revenue Sharing with Partners <a class="header-anchor" href="#🤝-revenue-sharing-with-partners" aria-label="Permalink to &quot;🤝 Revenue Sharing with Partners&quot;">​</a></h4><p>If you’ve enabled the <strong>Partnership Module</strong>, you can further divide the platform’s share of the commission with <strong>third-party partners</strong> such as:</p><ul><li>Vehicle owners</li><li>Marketing affiliates</li><li>Regional fleet operators</li></ul><p><strong>Example Scenario:</strong></p><ul><li>Trip fare: <code>$20.00</code></li><li>Commission: 20% (<code>$4.00</code>)</li><li>Partner share: 40% of commission → <code>$1.60</code></li><li>Platform keeps: <code>$2.40</code></li></ul><blockquote><p>These rules are defined per partner and calculated automatically during settlement.</p></blockquote><hr><h4 id="💼-where-it-s-configured" tabindex="-1">💼 Where It’s Configured <a class="header-anchor" href="#💼-where-it-s-configured" aria-label="Permalink to &quot;💼 Where It’s Configured&quot;">​</a></h4><p>You define commission and incentive rules in:</p><blockquote><p><strong>Management → Pricing → Commission Settings</strong></p></blockquote><ul><li>Applies globally to all drivers using that service in the associated region</li><li>Reflected in driver earnings reports, invoices, and the Admin Panel</li></ul><p>If the <strong>Partnership Add-on</strong> is active:</p><blockquote><p>Navigate to <strong>Partners</strong> to define per-partner rules</p></blockquote><hr><h4 id="📝-summary-1" tabindex="-1">📝 Summary <a class="header-anchor" href="#📝-summary-1" aria-label="Permalink to &quot;📝 Summary&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Flat Commission</strong></td><td>Fixed fee per trip (e.g., $1.00)</td></tr><tr><td><strong>Percent Commission</strong></td><td>Percentage of total trip fare (e.g., 10%)</td></tr><tr><td><strong>Both Combined</strong></td><td>Allowed and applied cumulatively</td></tr><tr><td><strong>Partner Share</strong></td><td>Optional slice of the commission (e.g., 40%)</td></tr><tr><td><strong>Defined Per Service</strong></td><td>Configurable within each pricing definition</td></tr><tr><td><strong>Settlement Visibility</strong></td><td>Shown to Admin and Driver in reports</td></tr></tbody></table>',78)]))}const p=t(n,[["render",a]]);export{u as __pageData,p as default};
